def _unicode(text):
    if sys.version_info[0] == 3:
        if type(text) in (bytes, bytearray):
            return str(text, "utf-8")
        elif type(text) == str:
            return text
        else:
            return str(text)

    elif sys.version_info[0] ==2:
        if type(text) in (str,):
            return unicode(text, "utf-8")
        elif type(text) == unicode:
            return text
        else:
            return unicode(text)

