def rotation_matrix_quat(system, part):
    A = np.zeros((3, 3))
    quat = system.part[part].quat
    qq = np.power(quat, 2)
    A[0, 0] = qq[0] + qq[1] - qq[2] - qq[3]
    A[1, 1] = qq[0] - qq[1] + qq[2] - qq[3]
    # ... 
    return A

